	UPDATE TORDER_INFO_SO_RSLT_HD
	   SET OR_WK_STATUS_CD = #{or_wk_status_cd}
		  ,UPDATEDATE = #{sysdate}
		  ,UPDATEURKEY = #{surkey}
	 WHERE
		   SO_HDKEY = #{so_hdkey}
       AND OR_WK_TYPE_CD = #{or_wk_type_cd}

	UPDATE TORDER_INFO_SO_RSLT_DT
	   SET UPDATEDATE = #{sysdate}
		  ,UPDATEURKEY = #{surkey}
	 WHERE
		   SO_HDKEY = #{so_hdkey}
       AND SO_DTKEY = #{so_dtkey}
       AND OR_WK_TYPE_CD = #{or_wk_type_cd}
       AND OR_WK_TYPE_CD = #{so_rsltkey}

UPDATE TORDER_INFO_SO_HD
   SET UPDATEDATE = #{sysdate}
	  ,UPDATEURKEY = #{surkey}
	  ,OR_NOCHG_CD = #{or_nochg_cd}
 WHERE
	   SO_HDKEY = #{so_hdkey}

	UPDATE TORDER_INFO_SO_DT
	   SET UPDATEDATE = #{sysdate}
		  ,UPDATEURKEY = #{surkey}

			  ,CFQTY = CFQTY + #{cfqty}

	 WHERE
		   SO_HDKEY = #{so_hdkey}
       AND SO_DTKEY = #{so_dtkey}

		UPDATE 	TORDER_INFO_ASN_DT
		   SET 	UPDATEDATE = #{sysdate}
			  	,UPDATEURKEY = #{surkey}
              	,IBNRCD = #{ibnrcd}
              	,IBNRIMGKEY = #{ibnrimgkey}
		 		,IBCFQTY = #{ibcfqty}	
				,IBRJQTY = #{ibrjqty}	  
		 WHERE
		       SO_HDKEY = #{so_hdkey}
		   AND SO_DTKEY = #{so_dtkey}

		UPDATE 	TORDER_INFO_ASN_DT
		   SET 	UPDATEDATE = #{sysdate}
			  	,UPDATEURKEY = #{surkey}
              	,IBNRCD = #{ibnrcd}
		 WHERE
		       	SO_HDKEY = #{so_hdkey}
		   AND 	SO_DTKEY = #{so_dtkey}

		UPDATE TORDER_INFO_PO1_DT
		   SET 
			   IBYN = 'Y'
			  ,IBDATE = #{cfdate}
		 	  ,IBQTY = IBQTY + #{cfqty}
			  ,IBAMT = DATE_TRUNC('day', #{costprice} * (IBQTY + #{cfqty}))::DATE
   			  ,IBRPRSN = #{ibnrcd}
   			  ,IN_HM = #{ibcreatedate}
   			  ,IBCREATEDATE = #{ibcreatedate}
   			  ,IBCREATEURKEY = #{surkey}
		      ,UPDATEDATE = #{sysdate}
			  ,UPDATEURKEY = #{surkey}
		 WHERE 
		       POHDKEY = #{pohdkey}
		   AND PODTKEY = #{podtkey}
		   AND CTKEY = #{ctkey}

UPDATE 	TORDER_INFO_PO1_DT
   SET 	IBRPRSN = #{ibnrcd}
       	,UPDATEDATE = #{sysdate}
	   	,UPDATEURKEY = #{surkey}
 WHERE 
       	POHDKEY = #{pohdkey}
   AND 	PODTKEY = #{podtkey}
   AND 	CTKEY = #{ctkey}

UPDATE TORDER_INFO_RTNGAP
   SET 
	   STORE_CD			= #{store_cd}       
	  ,GAP_YMD          = TO_CHAR(CURRENT_TIMESTAMP + INTERVAL '1 days' , 'YYYYMMDD')
	  ,GAP_ID           = #{gap_id}         
	  ,GAP_SEQ_NO       = #{gap_seq_no}     
	  ,NAP_CD           = #{nap_cd}         
	  ,CUST_CD          = #{cust_cd}        
	  ,LARGE_CD         = #{large_cd}       
	  ,MID_CD           = #{mid_cd}         
	  ,SMALL_CD         = #{small_cd}       
	  ,PLU_CD           = #{plu_cd}         
	  ,TAX_ID           = #{tax_id}         
	  ,ITEM_WONGA       = #{item_wonga}     
	  ,ITEM_MAEGA       = #{item_maega}     
	  ,DGFW_QTY         = #{dgfw_qty}       
	  ,BUY_QTY          = #{buy_qty}        
	  ,GAP_QTY          = #{gap_qty}        
	  ,ORG_CHIT_NO      = #{org_chit_no}    
	  ,ORG_CHIT_SEQ	    = #{org_chit_seq} 
	  ,ORG_CHIT_YMD     = #{org_chit_ymd}
	  ,APPROVAL_ID      = #{approval_id}    
	  ,GAP_REASON       = #{gap_reason}    
	  ,GAP_REASON_WM    = #{gap_reason_wm} 
	  ,ACP_CONF_ID      = #{acp_conf_id}    
	  ,ORG_CHIT_ID      = #{org_chit_id}    
	  ,SEND_YN          = #{send_yn}        
	  ,SEND_DATE        = #{send_date}      
      ,UPDATEDATE 		= #{sysdate}
	  ,UPDATEURKEY 		= #{surkey}
 WHERE 
       SO_HDKEY = #{so_hdkey}
   AND SO_DTKEY = #{so_dtkey}
   AND CHIT_NO = #{chit_no}
   AND CHIT_SEQ = #{chit_seq}

